          { label: 'Equipes ativas',   value: teams.length,   color: '#22c55e' },
          { label: 'Equipes sem OS',   value: equipesSemOS,   color: equipesSemOS > 0 ? '#eab308' : '#22c55e' },
          { label: 'Cidades cobertas', value: cidades.length, color: '#a78bfa' },
        ].map((k, i) => (
          <div key={i}
