            Grade — {teams.length} equipes com OS na semana
          </SectionLabel>
          <div className="flex items-center gap-3 text-[10px] text-muted">
            {[['#22c55e','1-2'],['#eab308','3-4'],['#f97316','5-7'],['#ef4444','8+']].map(([c,l]) => (
              <span key={l} className="flex items-center gap-1">
