                                      ${d.isToday ? 'text-primary' : d.isWeekend ? 'text-muted/70' : 'text-muted'}
                                      ${d.isWeekend ? 'bg-white/[0.01]' : ''}`}>
                        <div>{d.dow}</div>
                        <div className={`text-[9px] font-normal mt-0.5 ${d.isToday ? 'text-primary/70' : ''}`}>
