                </thead>
                <tbody>
                  {teams.map((t, i) => (
                    <tr key={t.team}
                        className="border-b border-white/[0.06] hover:bg-white/[0.03] transition-colors"
                        style={{ animationDelay: `${i * 30}ms` }}>
