      <td className="px-3 py-3 text-right">
        <p className="font-mono font-bold text-[18px] leading-none" style={{ color }}>{eq.taxa}%</p>
        <div className="mt-1 h-1 w-14 ml-auto bg-white/[0.05] rounded-full overflow-hidden">
