                        </div>
                        <p className="text-[11px] text-muted/60 ml-3.5 uppercase tracking-[0.9px] font-mono truncate">{c.iface}</p>
                      </div>
                      <span className={`flex-shrink-0 text-[8px] font-black px-2.5 py-1 rounded-full tracking-widest border
