        {isOk && <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green opacity-60" />}
        <span className={`relative inline-flex rounded-full h-2 w-2 ${dot}`} />
      </span>
      {txt}
    </div>
  )
}

