﻿import type { ReactNode } from 'react'
import { Modal } from '../../components/ui/Modal'
import { Badge } from '../../components/ui/Badge'
import { fmtDate, situacaoVariant, FORN_LABEL, shortEquipe } from '../../lib/osFormat'
