                    <span className={`text-[10px] font-normal ${active ? 'text-secondary' : 'text-muted'}`}>
                      {rows.length}
                    </span>
                  </button>
                )
              })}
            </div>
          </div>

          {/* Preview */}
          {(() => {
            const opt    = FORNECEDOR_OPTS.find(f => f.value === tgFornecedor)
            const isForn = tgFornecedor === 'WES' || tgFornecedor === 'Instacable'
            const t      = new Date()
